-- Patchnote 0.7.7 — idempotent seed (ON CONFLICT DO NOTHING).
INSERT INTO "Patchnote" ("version", "type", "date", "titleEn", "titleFr", "entries") VALUES
('0.7.7', 'minor', '2026-04-27T00:00:00.000Z',
  'Customisable dashboard, plugin install metrics & live nav refresh',
  'Dashboard personnalisable, métriques d''install plugin & nav live',
  '[{"type":"feat","titleEn":"Customisable dashboard tabs and widgets","titleFr":"Onglets et widgets de dashboard personnalisables","descEn":"Each dashboard tab gains an optional icon picker (curated 56-icon set). Each widget gains a Pencil edit button in edit mode that opens a modal — set a custom title, pick an icon, or just toggle ''show header'' to surface the widget''s default title. Custom overrides survive drag/resize.","descFr":"Chaque onglet du dashboard peut recevoir une icône (set curated de 56 icônes). Chaque widget a un bouton crayon en mode édition qui ouvre une modale — titre custom, icône, ou simplement toggle ''afficher le header'' pour montrer le titre par défaut du widget. Les overrides survivent au drag/resize."},{"type":"feat","titleEn":"Live install count on the Discover tab","titleFr":"Nombre d''installs en direct sur Discover","descEn":"Discover cards now display the total number of GitHub release-asset downloads next to the star count. Free signal — GitHub increments the counter automatically on each install. Plugins that ship a tarball/HEAD source archive (instead of a Release asset) show 0 since GitHub doesn''t track those.","descFr":"Les cartes Discover affichent maintenant le nombre total de téléchargements d''assets GitHub Release à côté du compteur d''étoiles. Signal gratuit — GitHub incrémente le compteur automatiquement à chaque install. Les plugins qui shippent une archive tarball/HEAD source (au lieu d''un asset de Release) affichent 0 puisque GitHub ne tracke pas ceux-là."},{"type":"feat","titleEn":"Verbose request log toggle","titleFr":"Toggle de log de requêtes verbeux","descEn":"New opt-in toggle in Admin → Système → Instance → Debug that persists every /api/* response to AppLog with method, path, status, redirect Location, duration, IP and User-Agent. Useful for tracing OAuth round-trips or plugin proxy redirects on a live instance. Off by default; URLs and Referer scrubbed via the existing scrubSecrets pipeline. Disable as soon as you''re done — it does write to the DB.","descFr":"Nouveau toggle opt-in dans Admin → Système → Instance → Debug qui persiste chaque réponse /api/* dans AppLog avec méthode, path, status, Location de redirect, durée, IP et User-Agent. Utile pour tracer les round-trips OAuth ou les redirects de proxy plugin sur une instance live. Off par défaut ; les URLs et Referer sont scrubbés via le pipeline scrubSecrets existant. Désactive dès que t''as fini — ça écrit en DB."},{"type":"feat","titleEn":"Plugin tab URL sync","titleFr":"Sync URL des sous-onglets Plugins","descEn":"Admin → Plugins → Installed / Discover sub-tab now syncs to the URL via ?sub=. Refresh, bookmark or share a link and you land on the right tab.","descFr":"Le sous-onglet Installed / Discover dans Admin → Plugins se synchronise maintenant à l''URL via ?sub=. Refresh, bookmark ou partage un lien et tu atterris sur le bon onglet."},{"type":"fix","titleEn":"Live nav refresh on plugin toggle","titleFr":"Refresh nav live au toggle plugin","descEn":"Toggling a plugin on/off used to leave its nav entries / dashboard widgets stuck until F5. usePluginUI gains a pub/sub: invalidating the cache notifies every mounted hook so contributions refetch in place. The toggle pill itself shows a spinner with ''Enabling…'' / ''Disabling…'' copy while the request is in flight.","descFr":"Activer/désactiver un plugin laissait ses entrées de nav / widgets de dashboard figés jusqu''à F5. usePluginUI gagne un pub/sub : invalider le cache notifie chaque hook monté pour que les contributions se refetch en place. Le pill de toggle affiche un spinner avec ''Enabling…'' / ''Disabling…'' pendant la requête."},{"type":"fix","titleEn":"Stale ''update available'' badge","titleFr":"Badge ''update available'' obsolète","descEn":"After installing a fresh version (say v0.1.2), the badge would still claim ''v0.1.1 available'' until the 1h cache TTL passed — it compared with `latest !== installed` instead of strict semver. The check is now `latest > installed` (semver-aware) AND the cache invalidates on install/uninstall so the badge clears immediately.","descFr":"Après install d''une nouvelle version (disons v0.1.2), le badge continuait à dire ''v0.1.1 available'' jusqu''à expiration du cache d''1h — il comparait avec `latest !== installed` au lieu d''un vrai semver. Le check est maintenant `latest > installed` (semver-aware) ET le cache s''invalide à l''install/uninstall pour que le badge se nettoie immédiatement."},{"type":"fix","titleEn":"Update resolver follows /releases when /latest 404s","titleFr":"Le résolveur d''update suit /releases si /latest 404","descEn":"GitHub returns 404 on /releases/latest when no release is explicitly flagged as latest (some CI workflows skip the flag, plus transient API hiccups). The resolver now falls back to /releases?per_page=30 sorted by semver desc — same logic GitHub uses internally — so install and update both keep working.","descFr":"GitHub renvoie 404 sur /releases/latest quand aucune release n''est explicitement marquée latest (certains workflows CI skippent le flag, plus quelques hoquets transitoires de l''API). Le résolveur fallback maintenant sur /releases?per_page=30 trié par semver desc — même logique que GitHub utilise en interne — pour que install et update continuent de marcher."},{"type":"fix","titleEn":"Bust stale browser caches on version flip","titleFr":"Purge des caches navigateur obsolètes au changement de version","descEn":"Stale HTML cached for /api/* URLs (from a past misconfig) could load the SPA shell on backend routes and produce blank pages. The SPA fallback now sets Cache-Control: no-store on index.html, and /api/app/version sends Clear-Site-Data: ''cache'' when the client''s oscarr_v cookie doesn''t match the running version — Chrome/Firefox/Edge purge their HTTP cache for the site on the spot. Sessions, settings and JWT survive.","descFr":"Du HTML obsolète caché pour des URLs /api/* (d''un ancien misconfig) pouvait charger le shell SPA sur des routes backend et produire des pages blanches. Le fallback SPA set maintenant Cache-Control: no-store sur index.html, et /api/app/version envoie Clear-Site-Data: ''cache'' quand le cookie oscarr_v du client ne matche pas la version courante — Chrome/Firefox/Edge purgent leur cache HTTP pour le site immédiatement. Sessions, settings et JWT survivent."},{"type":"fix","titleEn":"Logs ''Copy'' button works on LAN dev","titleFr":"Bouton ''Copier'' des logs marche en dev LAN","descEn":"navigator.clipboard requires a secure context (HTTPS or localhost). Dev over a LAN IP had no clipboard, so the button silently failed. New helper falls back to document.execCommand(''copy'') via a hidden textarea so the copy works on plain HTTP origins.","descFr":"navigator.clipboard exige un secure context (HTTPS ou localhost). Le dev sur une IP LAN n''avait pas de clipboard, le bouton échouait silencieusement. Nouveau helper avec fallback sur document.execCommand(''copy'') via un textarea caché pour que la copie marche sur du HTTP plain."}]'
) ON CONFLICT ("version") DO NOTHING;
